class LmdbThemeTopRegressionSnapshotTest {

	private static final Pattern THEME_HEADER = Pattern.compile("## ([A-Z_]+)");
	private static final Pattern QUERY_HEADER = Pattern.compile("### (?:([A-Z_]+) )?Query ([0-9]+)");
	private static final String ENABLED_PROPERTY = "rdf4j.lmdb.topRegressionSnapshot.enabled";
	private static final String QUERY_KEYS_PROPERTY = "rdf4j.lmdb.topRegressionSnapshot.queryKeys";
	private static final String RESULT_DIRECTORY = "src/test/java/org/eclipse/rdf4j/sail/lmdb/benchmark";
	private static final String SNAPSHOT_FILE = "lmdb-theme-fastest-run-optimized-queries-and-plans.md";
	private static final String PERSISTENT_STORE_KEY_PREFIX = "top-regression-snapshot";
	private static final String PERSISTENT_STORE_HINT = "Set -D"
			+ BenchmarkJoinEstimatorSupport.persistentThemeRegressionStoreEnabledPropertyName()
			+ "=true to reuse cached stores under persistent-lmdb-theme-store.";
	private static final List<TargetQuery> TOP_REGRESSIONS = List.of(
			target(Theme.PHARMA, 0),
			target(Theme.SOCIAL_MEDIA, 10),
			target(Theme.ELECTRICAL_GRID, 2),
			target(Theme.PHARMA, 5),
			target(Theme.LIBRARY, 2),
			target(Theme.TRAIN, 2),
			target(Theme.SOCIAL_MEDIA, 3),
			target(Theme.SOCIAL_MEDIA, 4),
			target(Theme.PHARMA, 10),
			target(Theme.SOCIAL_MEDIA, 6));

	@Test
	void topRegressionOptimizedQueriesMatchFastestKnownSnapshots(@TempDir Path dataDir) throws Exception {
		Map<String, String> fastestQueries = parseFastestOptimizedQueries();
		for (Map.Entry<Theme, List<TargetQuery>> entry : targetsByTheme().entrySet()) {
			System.out.println("Preparing theme " + entry.getKey());
			Path storeDirectory = prepareThemeStore(dataDir, entry.getKey());
			LmdbStore store = new LmdbStore(storeDirectory.toFile(), ConfigUtil.createConfig());
			SailRepository repository = new SailRepository(store);
			System.out.println("Prepared store for theme " + entry.getKey().name());
			try {
				for (TargetQuery targetQuery : entry.getValue()) {
					System.out.println("Checking optimized query for " + targetQuery.key());
					String expected = fastestQueries.get(targetQuery.key());
					assertTrue(expected != null, "Missing fastest optimized query snapshot for " + targetQuery.key());
					assertSnapshotMatchesWithinThirtySeconds(repository, targetQuery, expected);
					BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
				}
			} finally {
				shutdownAndRelease(repository, store);
				BenchmarkJoinEstimatorSupport.deleteStoreDirectory(storeDirectory);
			}
		}
	}

	private static Map<Theme, List<TargetQuery>> targetsByTheme() {
		Map<Theme, List<TargetQuery>> grouped = new LinkedHashMap<>();
		for (TargetQuery targetQuery : TOP_REGRESSIONS) {
			if (!isSelected(targetQuery)) {
				continue;
			}
			grouped.computeIfAbsent(targetQuery.theme, ignored -> new ArrayList<>())
					.add(targetQuery);
		}
		return grouped;
	}

	private static boolean isSelected(TargetQuery targetQuery) {
		String selectedKeys = System.getProperty(QUERY_KEYS_PROPERTY);
		if (selectedKeys == null || selectedKeys.isBlank()) {
			return true;
		}
		for (String selectedKey : selectedKeys.split(",")) {
			if (targetQuery.key().equals(selectedKey.strip())) {
				return true;
			}
		}
		return false;
	}

	private static Map<String, String> parseFastestOptimizedQueries() throws IOException {
		Map<String, String> queries = new LinkedHashMap<>();
		List<String> lines = Files.readAllLines(snapshotFile());
		Theme theme = null;
		int queryIndex = -1;
		for (int i = 0; i < lines.size(); i++) {
			String line = lines.get(i);
			Matcher themeMatcher = THEME_HEADER.matcher(line);
			if (themeMatcher.matches()) {
				theme = Theme.valueOf(themeMatcher.group(1));
				queryIndex = -1;
				continue;
			}
			Matcher queryMatcher = QUERY_HEADER.matcher(line);
			if (queryMatcher.matches()) {
				if (queryMatcher.group(1) != null) {
					theme = Theme.valueOf(queryMatcher.group(1));
				}
				queryIndex = Integer.parseInt(queryMatcher.group(2));
				continue;
			}
			if (theme != null && queryIndex >= 0 && line.equals("Optimized query:")) {
				Block block = readFencedBlock(lines, i + 1);
				if (block.text != null) {
					queries.put(theme.name() + ":" + queryIndex, block.text);
					i = block.nextIndex - 1;
				}
			}
		}
		return queries;
	}

	private static Block readFencedBlock(List<String> lines, int startIndex) {
		for (int i = startIndex; i < lines.size(); i++) {
			if (lines.get(i).equals("```sparql")) {
				List<String> block = new ArrayList<>();
				for (int j = i + 1; j < lines.size(); j++) {
					if (lines.get(j).equals("```")) {
						return new Block(String.join("\n", block), j + 1);
					}
					block.add(lines.get(j));
				}
			}
			if (lines.get(i).startsWith("### ") || lines.get(i).startsWith("## ")) {
				break;
			}
		}
		return new Block(null, lines.size());
	}

	private static Path snapshotFile() {
		Path basedirFile = Path.of(System.getProperty("basedir", "."), RESULT_DIRECTORY, SNAPSHOT_FILE);
		if (Files.isRegularFile(basedirFile)) {
			return basedirFile;
		}
		Path repositoryFile = Path.of("core/sail/lmdb", RESULT_DIRECTORY, SNAPSHOT_FILE);
		if (Files.isRegularFile(repositoryFile)) {
			return repositoryFile;
		}
		throw new AssertionError("Unable to locate fastest-run snapshot file " + SNAPSHOT_FILE);
	}

	private static Path prepareThemeStore(Path dataDir, Theme theme) throws Exception {
		BenchmarkJoinEstimatorSupport.ThemeRegressionStore preparedStore = BenchmarkJoinEstimatorSupport
				.prepareThemeRegressionStore(
						dataDir.resolve("top-regression-" + theme.name()),
						PERSISTENT_STORE_KEY_PREFIX + "/" + theme.name(),
						storeDirectory -> {
							LmdbStore store = new LmdbStore(storeDirectory.toFile(), ConfigUtil.createConfig());
							SailRepository repository = new SailRepository(store);
							try {
								BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
								loadData(repository, theme);
								BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);
								BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
							} finally {
								shutdownAndRelease(repository, store);
							}
						});
		if (preparedStore.reused()) {
			System.out.println("Reusing persistent store " + preparedStore.storeDirectory()
					+ " for top-regression snapshot " + theme.name() + ". " + PERSISTENT_STORE_HINT);
		}
		return preparedStore.storeDirectory();
	}

	private static void loadData(SailRepository repository, Theme theme) throws IOException {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.READ_COMMITTED);
			RDFInserter inserter = new RDFInserter(connection);
			ThemeDataSetGenerator.generate(theme, inserter);
			connection.commit();
		}
		System.out.println("Loaded data for theme " + theme.name());
	}

	private static String explainOptimized(SailRepository repository, TargetQuery targetQuery) {
		String query = ThemeQueryCatalog.queryFor(targetQuery.theme, targetQuery.queryIndex);
		try (SailRepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Optimized);
			return new TupleExprIRRenderer().render((TupleExpr) explanation.tupleExpr());
		}
	}

	private static void assertSnapshotMatchesWithinThirtySeconds(SailRepository repository, TargetQuery targetQuery,
			String expected) throws Exception {
		BenchmarkJoinEstimatorSupport.assertQueryRegressionPassesWithinThirtySeconds(targetQuery.key(), () -> {
			String actual = explainOptimized(repository, targetQuery);
			if (!normalize(expected).equals(normalize(actual))) {
				throw new AssertionError(
						mismatch(targetQuery, expected, actual) + "\nActual plan:\n"
								+ explainOptimizedPlan(repository, targetQuery));
			}
			assertKnownPlanShape(repository, targetQuery);
		});
	}

	private static void assertKnownPlanShape(SailRepository repository, TargetQuery targetQuery) {
		if (targetQuery.theme == Theme.PHARMA && targetQuery.queryIndex == 0) {
			String plan = explainOptimizedPlan(repository, targetQuery);
			assertPlanContains(plan, targetQuery.key(),
					"BindingSetAssignment ([[disease=http://example.com/theme/pharma/disease/0]",
					"value=http://example.com/theme/pharma/studiesDisease",
					"value=http://www.w3.org/1999/02/22-rdf-syntax-ns#type",
					"value=http://example.com/theme/pharma/hasArm",
					"value=http://example.com/theme/pharma/pValue",
					"value=http://example.com/theme/pharma/effectSize",
					"value=http://example.com/theme/pharma/biomarker, anonymous");
			assertPlanBefore(plan, targetQuery.key(),
					"value=http://example.com/theme/pharma/hasArm",
					"value=http://example.com/theme/pharma/armDrug");
			assertPlanBefore(plan, targetQuery.key(),
					"value=http://example.com/theme/pharma/hasArm",
					"value=http://example.com/theme/pharma/hasResult");
			assertPlanBefore(plan, targetQuery.key(),
					"value=http://example.com/theme/pharma/armDrug",
					"value=http://example.com/theme/pharma/pValue");
			assertPlanBefore(plan, targetQuery.key(),
					"value=http://example.com/theme/pharma/hasResult",
					"value=http://example.com/theme/pharma/pValue");
		}
	}

	private static String explainOptimizedPlan(SailRepository repository, TargetQuery targetQuery) {
		String query = ThemeQueryCatalog.queryFor(targetQuery.theme, targetQuery.queryIndex);
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Optimized)
					.toString();
		}
	}

	private static void assertPlanContains(String plan, String key, String... expectedParts) {
		for (String expectedPart : expectedParts) {
			assertTrue(plan.contains(expectedPart), key + " plan should contain " + expectedPart + ":\n" + plan);
		}
	}

	private static void assertPlanBefore(String plan, String key, String before, String after) {
		int beforeIndex = plan.indexOf(before);
		int afterIndex = plan.indexOf(after);
		assertTrue(beforeIndex >= 0, key + " plan missing " + before + ":\n" + plan);
		assertTrue(afterIndex >= 0, key + " plan missing " + after + ":\n" + plan);
		assertTrue(beforeIndex < afterIndex, key + " expected " + before + " before " + after + ":\n" + plan);
	}

	private static String normalize(String query) {
		return query.lines()
				.map(String::strip)
				.filter(line -> !line.isEmpty())
				.map(line -> line.replaceAll("_anon_(path|having)_[A-Za-z0-9]+", "_anon_$1"))
				.collect(Collectors.joining("\n"));
	}

	private static String mismatch(TargetQuery targetQuery, String expected, String actual) {
		return targetQuery.key() + " optimized query differs from fastest known snapshot\nExpected:\n"
				+ expected + "\nActual:\n" + actual;
	}

	private static void shutdownAndRelease(SailRepository repository, LmdbStore store) throws IOException {
		try {
			BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		} finally {
			repository.shutDown();
		}
	}

	private static TargetQuery target(Theme theme, int queryIndex) {
		return new TargetQuery(theme, queryIndex);
	}

	private static final class TargetQuery {
		private final Theme theme;
		private final int queryIndex;

		private TargetQuery(Theme theme, int queryIndex) {
			this.theme = theme;
			this.queryIndex = queryIndex;
		}

		private String key() {
			return theme.name() + ":" + queryIndex;
		}
	}

	private static final class Block {
		private final String text;
		private final int nextIndex;

		private Block(String text, int nextIndex) {
			this.text = text;
			this.nextIndex = nextIndex;
		}
	}
}
